const __testDir = dirname(fileURLToPath(import.meta.url));
function srcPath(relativePath: string): string {
  return join(__testDir, relativePath);
}

function formatFooterIndexLabel(language: "zh-CN" | "en-US", status: string): string {
  const trimmed = (status ?? "").trim();
  if (!trimmed || trimmed.toLowerCase() === "unknown")
    return language === "en-US" ? "Index?" : "索引?";
  if (trimmed === "refresh_completed_but_unverified")
    return `${language === "en-US" ? "Index" : "索引"} refresh`;
  return `${language === "en-US" ? "Index" : "索引"} ${trimmed.length > 10 ? `${trimmed.slice(0, 4)}…${trimmed.slice(-5)}` : trimmed}`;
}

function readSrc(relativePath: string): Promise<string> {
  return readFile(srcPath(relativePath), "utf8");
}

class MemoryOutput extends Writable {
  text = "";

  override _write(chunk: Buffer | string, _encoding: BufferEncoding, callback: () => void): void {
    this.text += chunk.toString();
    callback();
  }
}

class TtyOutput extends MemoryOutput {
  isTTY = true;
}

class TtyInput extends PassThrough {
  isTTY = true;
  isRaw = false;

  setRawMode(enabled: boolean): this {
    this.isRaw = enabled;
    return this;
  }
}

function isDeepCompactRequest(request: unknown): boolean {
  return JSON.stringify(request).includes("deep context compact agent");
}

function nonDeepRequests<T>(requests: T[]): T[] {
  return requests.filter((request) => !isDeepCompactRequest(request));
}

function createTestModelConfig(overrides: Partial<LinghunConfig> = {}): LinghunConfig {
  return {
    ...defaultConfig,
    ...overrides,
    providers: {
      ...defaultConfig.providers,
      "openai-compatible-vision": {
        type: "openai-compatible",
        baseUrl: "https://example.invalid/v1",
        apiKey: "sk-test-vision",
        model: "gpt-4o",
      },
      "openai-compatible-image": {
        type: "openai-compatible",
        baseUrl: "https://example.invalid/v1",
        apiKey: "sk-test-image",
        model: "gpt-image-1",
      },
      ...overrides.providers,
    },
    modelRoutes: {
      ...defaultConfig.modelRoutes,
      ...overrides.modelRoutes,
      routes: [...defaultConfig.modelRoutes.routes, ...(overrides.modelRoutes?.routes ?? [])],
    },
  };
}

function setTestRoleRoute(
  context: TuiContext,
  role: "vision" | "image",
  provider: string,
  model: string,
): void {
  if (provider === "openai-compatible-vision") {
    context.config.providers[provider] = {
      type: "openai-compatible",
      baseUrl: "https://example.invalid/v1",
      apiKey: "sk-test-vision",
      model,
    };
  }
  if (provider === "openai-compatible-image") {
    context.config.providers[provider] = {
      type: "openai-compatible",
      baseUrl: "https://example.invalid/v1",
      apiKey: "sk-test-image",
      model,
    };
  }
  context.config.modelRoutes.routes = context.config.modelRoutes.routes.map((route) =>
    route.role === role ? { ...route, provider, primaryModel: model } : route,
  );
}

