function mockOpenAiToolSequenceWithFinalCalls(
  toolCalls: Array<{ toolName: string; input: unknown }>,
  finalText = "done",
): unknown[] {
  const requests: unknown[] = [];
  vi.stubGlobal(
    "fetch",
    vi.fn(async (_url: string, init: RequestInit) => {
      requests.push(JSON.parse(String(init.body)));
      const request = JSON.parse(String(init.body)) as {
        tool_choice?: string;
        toolChoice?: string;
      };
      const finalOnly = request.tool_choice === "none" || request.toolChoice === "none";
      const toolIndex = requests.filter((item) => {
        const req = item as { tool_choice?: string; toolChoice?: string };
        return req.tool_choice !== "none" && req.toolChoice !== "none";
      }).length;
      const toolCall = finalOnly ? undefined : toolCalls[toolIndex - 1];
      const body = toolCall
        ? [
            `data: ${JSON.stringify({
              id: `chatcmpl-test-${requests.length}`,
              choices: [
                {
                  delta: {
                    tool_calls: [
                      {
                        id: `call-${requests.length}`,
                        type: "function",
                        function: {
                          name: toolCall.toolName,
                          arguments: JSON.stringify(toolCall.input),
                        },
                      },
                    ],
                  },
                },
              ],
            })}\n\n`,
            "data: [DONE]\n\n",
          ].join("")
        : `data: ${JSON.stringify({ id: `chatcmpl-test-${requests.length}`, choices: [{ delta: { content: finalText } }] })}\n\ndata: [DONE]\n\n`;
      return new Response(body, { status: 200, headers: { "content-type": "text/event-stream" } });
    }),
  );
  return requests;
}

function mockOpenAiLongHistoryThenToolFetch(): unknown[] {
  const requests: unknown[] = [];
  vi.stubGlobal(
    "fetch",
    vi.fn(async (_url: string, init: RequestInit) => {
      const request = JSON.parse(String(init.body));
      requests.push(request);
      const isDeepCompact = isDeepCompactRequest(request);
      const mainRequestCount = nonDeepRequests(requests).length;
      let body: string;
      if (isDeepCompact) {
        body = `data: ${JSON.stringify({ id: "chatcmpl-compact-deep", choices: [{ delta: { content: "Deep compact summary for tool pair context." } }] })}\n\ndata: [DONE]\n\n`;
      } else if (mainRequestCount === 1) {
        const text = `RAW_TOOL_PAIR_CONTEXT_SHOULD_NOT_REACH_PROVIDER\n${"旧上下文\n".repeat(60_000)}`;
        body = `data: ${JSON.stringify({ id: "chatcmpl-compact-tool-1", choices: [{ delta: { content: text } }] })}\n\ndata: [DONE]\n\n`;
      } else if (mainRequestCount === 2) {
        body = [
          `data: ${JSON.stringify({
            id: "chatcmpl-compact-tool-2",
            choices: [
              {
                delta: {
                  tool_calls: [
                    {
                      id: "call-compact-read",
                      type: "function",
                      function: { name: "Read", arguments: JSON.stringify({ path: "pair.txt" }) },
                    },
                  ],
                },
              },
            ],
          })}\n\n`,
          "data: [DONE]\n\n",
        ].join("");
      } else {
        body = `data: ${JSON.stringify({ id: "chatcmpl-compact-tool-3", choices: [{ delta: { content: "pairing ok" } }] })}\n\ndata: [DONE]\n\n`;
      }
      return new Response(body, { status: 200, headers: { "content-type": "text/event-stream" } });
    }),
  );
  return requests;
}

function mockOpenAiResponsesLongHistoryThenToolFetch(): unknown[] {
  const requests: unknown[] = [];
  vi.stubGlobal(
    "fetch",
    vi.fn(async (_url: string, init: RequestInit) => {
      const request = JSON.parse(String(init.body));
      requests.push(request);
      const isDeepCompact = isDeepCompactRequest(request);
      const mainRequestCount = nonDeepRequests(requests).length;
      let body: string;
      if (isDeepCompact) {
        body = [
          `data: ${JSON.stringify({ type: "response.output_text.delta", delta: "Deep compact summary for responses pair context." })}\n\n`,
          `data: ${JSON.stringify({ type: "response.completed", response: { id: "resp-compact-deep", usage: { input_tokens: 10, output_tokens: 10, total_tokens: 20 } } })}\n\n`,
        ].join("");
      } else if (mainRequestCount === 1) {
        const text = `RAW_RESPONSES_PAIR_CONTEXT_SHOULD_NOT_REACH_PROVIDER\n${"旧上下文\n".repeat(60_000)}`;
        body = [
          `data: ${JSON.stringify({ type: "response.output_text.delta", delta: text })}\n\n`,
          `data: ${JSON.stringify({ type: "response.completed", response: { id: "resp-compact-1", usage: { input_tokens: 10, output_tokens: 10, total_tokens: 20 } } })}\n\n`,
        ].join("");
      } else if (mainRequestCount === 2) {
        body = [
          `data: ${JSON.stringify({ type: "response.output_item.added", output_index: 0, item: { type: "function_call", call_id: "call-compact-bash", name: "Bash" } })}\n\n`,
          `data: ${JSON.stringify({ type: "response.function_call_arguments.delta", output_index: 0, delta: JSON.stringify({ command: "echo responses pair content" }) })}\n\n`,
          `data: ${JSON.stringify({ type: "response.output_item.done", output_index: 0, item: { type: "function_call", call_id: "call-compact-bash", name: "Bash" } })}\n\n`,
          `data: ${JSON.stringify({ type: "response.completed", response: { id: "resp-compact-2", usage: { input_tokens: 10, output_tokens: 10, total_tokens: 20 } } })}\n\n`,
        ].join("");
      } else {
        body = [
          `data: ${JSON.stringify({ type: "response.output_text.delta", delta: "responses pairing ok" })}\n\n`,
          `data: ${JSON.stringify({ type: "response.completed", response: { id: "resp-compact-3", usage: { input_tokens: 10, output_tokens: 10, total_tokens: 20 } } })}\n\n`,
        ].join("");
      }
      return new Response(body, { status: 200, headers: { "content-type": "text/event-stream" } });
    }),
  );
  return requests;
}

function mockOpenAiStartAgentChildToolSequence(
  childToolCount: number,
  childFinalText?: string,
): unknown[] {
  const requests: unknown[] = [];
  const requestText = (request: unknown): string => JSON.stringify(request);
  const isChildAgentRequest = (request: unknown): boolean =>
    requestText(request).includes("child agent running in an isolated sidechain transcript");
  vi.stubGlobal(
    "fetch",
    vi.fn(async (_url: string, init: RequestInit) => {
      const request = JSON.parse(String(init.body)) as {
        messages?: Array<{ role?: string; content?: string }>;
        tool_choice?: string;
        toolChoice?: string;
      };
      requests.push(request);
      const finalOnly = request.tool_choice === "none" || request.toolChoice === "none";
      const isChildLoop = isChildAgentRequest(request);
      let body: string;
      if (requests.length === 1) {
        body = [
          `data: ${JSON.stringify({
            id: "chatcmpl-start-agent",
            choices: [
              {
                delta: {
                  tool_calls: [
                    {
                      id: "call-start-agent",
                      type: "function",
                      function: {
                        name: "StartAgent",
                        arguments: JSON.stringify({
                          role: "worker",
                          task: "连续读取 a.txt 后总结",
                        }),
                      },
                    },
                  ],
                },
              },
            ],
          })}\n\n`,
          "data: [DONE]\n\n",
        ].join("");
      } else if (isChildLoop) {
        const childToolRequests = requests.filter((item) => {
          const childRequest = item as {
            messages?: Array<{ role?: string; content?: string }>;
            tool_choice?: string;
            toolChoice?: string;
          };
          const childFinalOnly =
            childRequest.tool_choice === "none" || childRequest.toolChoice === "none";
          return !childFinalOnly && isChildAgentRequest(childRequest);
        }).length;
        if (!finalOnly && childToolRequests <= childToolCount) {
          body = [
            `data: ${JSON.stringify({
              id: `chatcmpl-child-${childToolRequests}`,
              choices: [
                {
                  delta: {
                    tool_calls: [
                      {
                        id: `call-child-read-${childToolRequests}`,
                        type: "function",
                        function: {
                          name: "Read",
                          arguments: JSON.stringify({ path: "a.txt" }),
                        },
                      },
                    ],
                  },
                },
              ],
            })}\n\n`,
            "data: [DONE]\n\n",
          ].join("");
        } else {
          body = `data: ${JSON.stringify({ id: "chatcmpl-child-final", choices: [{ delta: { content: childFinalText ?? "child done" } }] })}\n\ndata: [DONE]\n\n`;
        }
      } else {
        body = `data: ${JSON.stringify({ id: "chatcmpl-main-final", choices: [{ delta: { content: "主 agent 续轮完成。" } }] })}\n\ndata: [DONE]\n\n`;
      }
      return new Response(body, { status: 200, headers: { "content-type": "text/event-stream" } });
    }),
  );
  return requests;
}

function createStartAgentChildFallbackConfig(
  primaryModel = "child-primary-model",
  fallbackModel = "child-fallback-model",
): LinghunConfig {
  return {
    ...defaultConfig,
    defaultModel: primaryModel,
    providers: {
      ...defaultConfig.providers,
      deepseek: { ...defaultConfig.providers.deepseek, model: "different-model" },
      "openai-compatible": {
        ...defaultConfig.providers["openai-compatible"],
        baseUrl: "https://example.test/v1",
        apiKey: "sk-test",
        model: primaryModel,
      },
    },
    modelRoutes: {
      ...defaultConfig.modelRoutes,
      defaultModel: primaryModel,
      routes: defaultConfig.modelRoutes.routes.map((route) =>
        route.role === "executor"
          ? {
              ...route,
              provider: "openai-compatible",
              primaryModel,
              fallbackModels: [fallbackModel],
              allowTools: true,
            }
          : route,
      ),
    },
  };
}

function mockOpenAiStartAgentChildFallbackFetch(options: {
  primaryModel?: string;
  fallbackModel?: string;
  primaryResponse: Response;
  fallbackResponse?: Response;
  childFallbackFinalText?: string;
  mainFinalText?: string;
}): unknown[] {
  const primaryModel = options.primaryModel ?? "child-primary-model";
  const fallbackModel = options.fallbackModel ?? "child-fallback-model";
  const requests: unknown[] = [];
  const requestText = (request: unknown): string => JSON.stringify(request);
  const isChildAgentRequest = (request: unknown): boolean =>
    requestText(request).includes("child agent running in an isolated sidechain transcript");
  const textStream = (id: string, text: string): string =>
    `data: ${JSON.stringify({ id, choices: [{ delta: { content: text } }] })}\n\ndata: [DONE]\n\n`;
  const startAgentToolStream = [
    `data: ${JSON.stringify({
      id: "chatcmpl-start-agent",
      choices: [
        {
          delta: {
            tool_calls: [
              {
                id: "call-start-agent",
                type: "function",
                function: {
                  name: "StartAgent",
                  arguments: JSON.stringify({
                    role: "worker",
                    task: "use child provider fallback",
                  }),
                },
              },
            ],
          },
        },
      ],
    })}\n\n`,
    "data: [DONE]\n\n",
  ].join("");
  vi.stubGlobal(
    "fetch",
    vi.fn(async (_url: string, init: RequestInit) => {
      const request = JSON.parse(String(init.body));
      requests.push(request);
      if (isChildAgentRequest(request)) {
        const model = (request as { model?: string }).model;
        if (model === primaryModel) return options.primaryResponse;
        if (model === fallbackModel) {
          return (
            options.fallbackResponse ??
            new Response(
              textStream(
                "chatcmpl-child-fallback",
                options.childFallbackFinalText ?? "fallback child final",
              ),
              { status: 200, headers: { "content-type": "text/event-stream" } },
            )
          );
        }
      }
      if (requests.length === 1) {
        return new Response(startAgentToolStream, {
          status: 200,
          headers: { "content-type": "text/event-stream" },
        });
      }
      return new Response(
        textStream("chatcmpl-main-final", options.mainFinalText ?? "StartAgent final ok"),
        { status: 200, headers: { "content-type": "text/event-stream" } },
      );
    }),
  );
  return requests;
}

