  it("/agents resume restarts stale AgentRun without replaying old tool results", async () => {
    const project = await mkdtemp(join(tmpdir(), "linghun-agent-stale-resume-"));
    const config = createOpenAiRegistryAgentConfig("route-model");
    const store = new SessionStore({ sessionRootDir: getSessionRootDir(), projectPath: project });
    const session = await store.create({ model: "route-model" });
    const output = new MemoryOutput();
    const context = await createTestContext(project, store, session, config);
    context.modelGateway = createModelGateway(config);
    const timer = vi
      .spyOn(globalThis, "setTimeout")
      .mockImplementation((() => 0) as unknown as typeof setTimeout);

    await handleSlashCommand(
      "/fork worker stale resume target --background --name stale-resume",
      context,
      output,
    );
    timer.mockRestore();
    const running = context.agents[0];
    expect(running?.status).toBe("running");
    await store.appendEvent(running?.transcriptSessionId ?? "", {
      type: "tool_result",
      toolUseId: "old-tool-use",
      toolName: "Read",
      content: "old result must stay historical only",
      isError: false,
      createdAt: new Date().toISOString(),
    });

    const freshContext = await createTestContext(project, store, session, config);
    freshContext.modelGateway = createModelGateway(config);
    const { hydratePersistentAgents } = await import("./job-agent-command-runtime.js");
    await hydratePersistentAgents(freshContext);
    const stale = freshContext.agents.find((agent) => agent.addressableName === "stale-resume");
    expect(stale?.status).toBe("stale");
    mockOpenAiTextFetch("resumed fresh answer");

    await handleSlashCommand(`/agents resume ${stale?.id}`, freshContext, output);

    expect(stale?.status).toBe("idle");
    expect(stale?.summary).toContain("resumed fresh answer");
    const transcript = (await store.resume(stale?.transcriptSessionId ?? "")).transcript;
    const oldToolResults = transcript.filter(
      (event) => event.type === "tool_result" && event.toolUseId === "old-tool-use",
    );
    expect(oldToolResults).toHaveLength(1);
  });

  it("hydratePersistentAgents keeps terminal history out of main-screen background tasks", async () => {
    const project = await mkdtemp(join(tmpdir(), "linghun-agent-status-restore-"));
    const store = new SessionStore({ sessionRootDir: getSessionRootDir(), projectPath: project });
    const session = await store.create({ model: "gpt-4o" });
    const { hydratePersistentAgents } = await import("./job-agent-command-runtime.js");

    const context = await createTestContext(project, store, session);
    const config = await loadConfig(project);
    const agentRunsDir = resolveStoragePaths(config, project).agentRuns;
    await mkdir(agentRunsDir, { recursive: true });

    const now = new Date().toISOString();
    const blockedAgent = {
      id: "agent-blocked-01",
      type: "worker",
      status: "blocked",
      task: "blocked task",
      summary: "blocked by permission",
      role: "executor",
      transcriptPath: join(project, "agent-blocked-01.jsonl"),
      transcriptSessionId: session.id,
      startedAt: now,
      updatedAt: now,
    };
    const cancelledAgent = {
      id: "agent-cancelled-02",
      type: "worker",
      status: "cancelled",
      task: "cancelled task",
      summary: "user cancelled",
      role: "executor",
      transcriptPath: join(project, "agent-cancelled-02.jsonl"),
      transcriptSessionId: session.id,
      startedAt: now,
      updatedAt: now,
    };
    const failedAgent = {
      id: "agent-failed-03",
      type: "worker",
      status: "failed",
      task: "failed task",
      summary: "failed with error",
      role: "executor",
      transcriptPath: join(project, "agent-failed-03.jsonl"),
      transcriptSessionId: session.id,
      startedAt: now,
      updatedAt: now,
    };
    const completedAgent = {
      id: "agent-completed-04",
      type: "worker",
      status: "completed",
      task: "completed task",
      summary: "completed successfully",
      role: "executor",
      transcriptPath: join(project, "agent-completed-04.jsonl"),
      transcriptSessionId: session.id,
      startedAt: now,
      updatedAt: now,
    };
    const runningAgent = {
      id: "agent-running-05",
      type: "worker",
      status: "running",
      task: "running task",
      summary: "still running",
      role: "executor",
      transcriptPath: join(project, "agent-running-05.jsonl"),
      transcriptSessionId: session.id,
      startedAt: now,
      updatedAt: now,
    };

    await writeFile(
      join(agentRunsDir, "agent-blocked-01.json"),
      JSON.stringify(blockedAgent, null, 2),
    );
    await writeFile(
      join(agentRunsDir, "agent-cancelled-02.json"),
      JSON.stringify(cancelledAgent, null, 2),
    );
    await writeFile(
      join(agentRunsDir, "agent-failed-03.json"),
      JSON.stringify(failedAgent, null, 2),
    );
    await writeFile(
      join(agentRunsDir, "agent-completed-04.json"),
      JSON.stringify(completedAgent, null, 2),
    );
    await writeFile(
      join(agentRunsDir, "agent-running-05.json"),
      JSON.stringify(runningAgent, null, 2),
    );

    await hydratePersistentAgents(context);

    // Verify agent status restoration: only running→stale agents are hydrated.
    // Terminal agents (blocked, cancelled, failed, completed) are NOT loaded
    // into context.agents — their disk files are cleaned up by hydration.
    const restoredBlocked = context.agents.find((a) => a.id === "agent-blocked-01");
    const restoredCancelled = context.agents.find((a) => a.id === "agent-cancelled-02");
    const restoredFailed = context.agents.find((a) => a.id === "agent-failed-03");
    const restoredCompleted = context.agents.find((a) => a.id === "agent-completed-04");
    const restoredRunning = context.agents.find((a) => a.id === "agent-running-05");

    expect(restoredBlocked).toBeUndefined();
    expect(restoredCancelled).toBeUndefined();
    expect(restoredFailed).toBeUndefined();
    expect(restoredCompleted).toBeUndefined();
    expect(restoredRunning?.status).toBe("stale"); // running -> stale on restore

    // Only the stale/resumable agent gets a background task.
    // for /agents, while stale/resumable reaches the background surface so the
    // user can inspect or dismiss it explicitly.
    const bgBlocked = context.backgroundTasks.find((t) => t.id === "agent-blocked-01");
    const bgCancelled = context.backgroundTasks.find((t) => t.id === "agent-cancelled-02");
    const bgFailed = context.backgroundTasks.find((t) => t.id === "agent-failed-03");
    const bgCompleted = context.backgroundTasks.find((t) => t.id === "agent-completed-04");
    const bgStale = context.backgroundTasks.find((t) => t.id === "agent-running-05");

    expect(bgBlocked).toBeUndefined();
    expect(bgCancelled).toBeUndefined();
    expect(bgFailed).toBeUndefined();
    expect(bgCompleted).toBeUndefined();

    expect(bgStale).toEqual(
      expect.objectContaining({
        id: "agent-running-05",
        kind: "agent",
        status: "stale",
        result: "partial",
      }),
    );

    const backgroundOutput = new MemoryOutput();
    await handleSlashCommand("/background", context, backgroundOutput);
    expect(backgroundOutput.text).toContain("Agent running-worker");
    expect(backgroundOutput.text).toContain("stale");
    expect(backgroundOutput.text).not.toContain("没有后台任务");

    const snapshot = (await import("./runtime-status-snapshot.js")).createRuntimeStatusSnapshot({
      language: context.language,
      backgroundTasks: context.backgroundTasks,
    });
    expect(snapshot.activeAgents).toEqual([]);
    expect(snapshot.staleResumableTasks.map((item) => item.id)).toEqual(["agent-running-05"]);
  });

