  it("guards foreground model requests and heavyweight background resource caps", async () => {
    const project = await mkdtemp(join(tmpdir(), "linghun-tui-project-"));
    const store = new SessionStore({ sessionRootDir: getSessionRootDir(), projectPath: project });
    const session = await store.create({ model: "deepseek-v4-flash" });
    const output = new MemoryOutput();
    const context = await createTestContext(project, store, session);
    context.permissionMode = "full-access";

    context.activeAbortController = new AbortController();
    await expect(handleNaturalInput("普通模型请求", context, output)).resolves.toBe("handled");
    expect(output.text).toContain("已有前台模型请求正在运行");
    context.activeAbortController = undefined;

    context.backgroundTasks = Array.from({ length: 50 }, (_, index) =>
      createBackgroundTaskFixture(index % 2 === 0 ? "compact" : "bash", {
        id: `heavy-${index}`,
      }),
    );
    await handleSlashCommand("/verify smoke", context, output);
    expect(output.text).toContain("后台任务已达到全局上限 50");

    context.backgroundTasks = [createBackgroundTaskFixture("bash")];
    await handleSlashCommand("/bash node --version", context, output);
    // Per-kind caps removed — bash no longer blocked by the old cap=1 limit.
    // Heavy check still applies: only one heavy operation at a time.
    expect(output.text).toContain("已有 bash 重任务正在运行");
    expect(output.text).not.toContain("bash 后台任务已达到上限");

    context.backgroundTasks = [createBackgroundTaskFixture("verification")];
    await handleSlashCommand("/verify smoke", context, output);
    // Per-kind caps removed — verification no longer blocks on a single running verification.
    expect(output.text).not.toContain("verification 后台任务已达到上限");

    const indexTaskNow = new Date().toISOString();
    context.backgroundTasks = [
      createBackgroundTaskFixture("index", { updatedAt: indexTaskNow, lastOutputAt: indexTaskNow }),
    ];
    context.permissionMode = "full-access";
    await handleSlashCommand("/index refresh", context, output);
    // Per-kind caps removed — index no longer blocks on a single running index task.
    expect(output.text).not.toContain("index 后台任务已达到上限");

    output.text = "";
    context.backgroundTasks = Array.from({ length: 6 }, (_, index) =>
      createBackgroundTaskFixture("agent", { id: `agent-running-${index}` }),
    );
    await handleSlashCommand("/fork explorer inspect cache", context, output);
    expect(output.text).not.toContain("agent 后台任务已达到上限 3");
    expect(output.text).not.toContain("最多同时运行 3 个 agent");

    output.text = "";
    context.backgroundTasks = [
      createBackgroundTaskFixture("agent", { status: "completed", currentStep: "idle" }),
      createBackgroundTaskFixture("agent"),
      createBackgroundTaskFixture("agent"),
    ];
    await handleSlashCommand("/fork explorer inspect idle cap", context, output);
    expect(output.text).not.toContain("最多同时运行 3 个 agent");

    output.text = "";
    context.backgroundTasks = [
      createBackgroundTaskFixture("agent", { status: "stale" }),
      createBackgroundTaskFixture("agent", { status: "stale" }),
      createBackgroundTaskFixture("agent", { status: "stale" }),
    ];
    await handleSlashCommand("/fork explorer stale history is not cap", context, output);
    expect(output.text).not.toContain("agent 后台任务已达到上限 3");

    context.backgroundTasks = [createBackgroundTaskFixture("verification")];
    await handleSlashCommand("/bash node --version", context, output);
    expect(output.text).toContain("已有 verification 重任务正在运行");
    expect(context.permissionMode).toBe("full-access");
  });

